concept.codeExample:
EXPLAIN ANALYZE SELECT * FROM orders WHERE customer_id = 42 ORDER BY created_at DESC LIMIT 10;
-- Create a multicolumn index to speed this up:
CREATE INDEX idx_orders_customer_created ON orders (customer_id, created_at DESC);
-- Make it covering (Postgres):
CREATE INDEX idx_orders_cover ON orders (customer_id, created_at DESC) INCLUDE (amount, status);
